public class LoginForm:Form{readonly TextBox user=new();readonly TextBox pass=new();readonly ComboBox role=new();public LoginForm(){Text="Premium Living Furniture ERP - Sign In";StartPosition=FormStartPosition.CenterScreen;Size=new Size(980,600);BackColor=Theme.AppBg;Font=Theme.DefaultFont;var root=new TableLayoutPanel{Dock=DockStyle.Fill,ColumnCount=2,Padding=new Padding(38),BackColor=Theme.AppBg};root.ColumnStyles.Add(new ColumnStyle(SizeType.Percent,43));root.ColumnStyles.Add(new ColumnStyle(SizeType.Percent,57));var hero=new Panel{Dock=DockStyle.Fill,BackColor=Theme.Primary,Padding=new Padding(30)};hero.Controls.Add(new Label{Text="Premium Living"+Environment.NewLine+"Furniture ERP",Dock=DockStyle.Top,Height=145,ForeColor=Color.White,Font=new Font("Segoe UI",26,FontStyle.Bold),BackColor=Theme.Primary});hero.Controls.Add(new Label{Text="Sales | Purchasing | Inventory | Delivery | Finance",Dock=DockStyle.Top,Height=70,ForeColor=Color.FromArgb(219,234,254),Font=new Font("Segoe UI",12),BackColor=Theme.Primary});var card=new Panel{Dock=DockStyle.Fill,BackColor=Color.White,Padding=new Padding(40),Margin=new Padding(24,0,0,0)};card.Controls.Add(Content());root.Controls.Add(hero,0,0);root.Controls.Add(card,1,0);Controls.Add(root);}Control Content(){var page=new TableLayoutPanel{Dock=DockStyle.Fill,RowCount=5,ColumnCount=1,BackColor=Color.White};page.RowStyles.Add(new RowStyle(SizeType.Absolute,75));page.RowStyles.Add(new RowStyle(SizeType.Absolute,230));page.RowStyles.Add(new RowStyle(SizeType.Absolute,70));page.Controls.Add(new Label{Text="Welcome back",Dock=DockStyle.Fill,Font=new Font("Segoe UI",24,FontStyle.Bold),ForeColor=Theme.Text,BackColor=Color.White},0,0);var form=new TableLayoutPanel{Dock=DockStyle.Fill,ColumnCount=1,BackColor=Color.White};pass.UseSystemPasswordChar=true;pass.Text="1234";role.DropDownStyle=ComboBoxStyle.DropDownList;role.Items.AddRange(new object[]{"Admin","Manager","Sales Staff","Logistics Clerk","Warehouse Clerk","Finance Staff","Customer Service"});role.SelectedIndexChanged+=(_,_)=>user.Text=role.Text switch{"Admin"=>"admin","Manager"=>"manager","Sales Staff"=>"sales01","Logistics Clerk"=>"logistics01","Warehouse Clerk"=>"warehouse01","Finance Staff"=>"finance01","Customer Service"=>"cs01",_=>""};role.SelectedIndex=0;Add(form,"Username",user);Add(form,"Password",pass);Add(form,"Role",role);page.Controls.Add(form,0,1);var buttons=new FlowLayoutPanel{Dock=DockStyle.Fill,BackColor=Color.White};var login=Theme.PrimaryButton("Login",125);var check=Theme.SecondaryButton("Check DB",125);login.Click+=(_,_)=>Login();check.Click+=(_,_)=>Check();buttons.Controls.Add(login);buttons.Controls.Add(check);page.Controls.Add(buttons,0,2);return page;}static void Add(TableLayoutPanel f,string label,Control c){f.RowStyles.Add(new RowStyle(SizeType.Absolute,24));f.RowStyles.Add(new RowStyle(SizeType.Absolute,54));f.Controls.Add(new Label{Text=label,Dock=DockStyle.Fill,ForeColor=Theme.Muted,Font=new Font("Segoe UI",9,FontStyle.Bold),BackColor=Color.White});c.Dock=DockStyle.Fill;c.Font=new Font("Segoe UI",11);c.Margin=new Padding(0,4,0,12);f.Controls.Add(c);}void Check(){try{MessageBox.Show(Database.TestConnectionDetailed(),"Database OK");}catch(Exception ex){MessageBox.Show(ex.Message);}}void Login(){try{if(!AuthService.Login(user.Text,pass.Text,role.Text)){MessageBox.Show("Login failed.");return;}Hide();var main=new MainForm(user.Text,role.Text);main.FormClosed+=(_,_)=>Close();main.Show();}catch(Exception ex){MessageBox.Show("Login/database failed: "+ex.Message);}}}
